  SharedPtr(SharedPtr&& other) noexcept;
  ~SharedPtr();
  SharedPtr& operator=(const SharedPtr& other);
  SharedPtr& operator=(SharedPtr&& other) noexcept;
  T* get() const;
  T& operator*() const;
  T* operator->() const;
  size_t use_count() const;
  void reset();
};
